__global__ void pgain_kernel(
    Point_Struct *p,
    float *coord_d,
    float *work_mem_d,
    int *center_table_d,
    char *switch_membership_d,
    int num,
    int dim,
    long x,
    int K)
{
  extern __shared__ float coord_s[];
  const int thread_id = blockIdx.x * blockDim.x + threadIdx.x;
  const int local_id = threadIdx.x;

  if (local_id == 0) {
    for (int i = 0; i < dim; i++) {
      coord_s[i] = coord_d[i * num + x];
    }
  }
  __syncthreads();

  if (thread_id < num) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = coord_d[i * num + thread_id] - coord_s[i];
      x_cost += diff * diff;
    }
    x_cost = x_cost * p[thread_id].weight;

    float current_cost = p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership_d[thread_id] = '1';
      int addr_1 = base + K;
      work_mem_d[addr_1] = x_cost - current_cost;
    } else {
      long assign = p[thread_id].assign;
      int addr_2 = base + center_table_d[(int)assign];
      work_mem_d[addr_2] += current_cost - x_cost;
    }
  }
}

