    throw std::string("InitCL()::Error: No devices found.");
  }
  if (dev < 0 || dev >= count) {
    throw std::string("Invalidate device id");
  }
  cudaCheck(cudaSetDevice(dev), "_clInit cudaSetDevice");
  cudaDeviceProp prop;
