static void ensure_capacity(int num, int dim, int kcap) {
  bool need_realloc = false;
  if (num > alloc_num || dim > alloc_dim || kcap > alloc_kcap) {
    need_realloc = true;
  }

  if (!need_realloc) return;

  double t1 = helper_gettime();
  free_all_buffers_internal();

  alloc_num = num;
  alloc_dim = dim;
  alloc_kcap = kcap;

  coord_h = (float*)malloc((size_t)alloc_num * alloc_dim * sizeof(float));
  gl_lower = (float*)malloc((size_t)alloc_kcap * sizeof(float));
  p_h = (Point_Struct*)malloc((size_t)alloc_num * sizeof(Point_Struct));

  if (coord_h == NULL || gl_lower == NULL || p_h == NULL) {
    throw std::string("Could not allocate host memory");
  }

  cudaCheck(cudaMallocHost((void**)&work_mem_h, (size_t)alloc_kcap * alloc_num * sizeof(float)), "cudaMallocHost work_mem_h");
  cudaCheck(cudaMalloc((void**)&work_mem_d, (size_t)alloc_kcap * alloc_num * sizeof(float)), "cudaMalloc work_mem_d");
  cudaCheck(cudaMalloc((void**)&center_table_d, (size_t)alloc_num * sizeof(int)), "cudaMalloc center_table_d");
  cudaCheck(cudaMalloc((void**)&switch_membership_d, (size_t)alloc_num * sizeof(char)), "cudaMalloc switch_membership_d");
  cudaCheck(cudaMalloc((void**)&p_d, (size_t)alloc_num * sizeof(Point_Struct)), "cudaMalloc p_d");
  cudaCheck(cudaMalloc((void**)&coord_d, (size_t)alloc_num * alloc_dim * sizeof(float)), "cudaMalloc coord_d");

  double t2 = helper_gettime();
  MA += t2 - t1;
}

extern "C" void allocDevMem(int num, int dim, int kmax){
  try{
    ensure_capacity(num, dim, kmax);
  }
  catch(std::string msg){
    quit((char*)msg.c_str());
  }
}

static void update_coords_if_needed(Points *points, double *cpu_gpu_memcpy) {
  int num = (int)points->num;
  int dim = points->dim;

  if (last_coord_source == points->p && last_coord_num == num && last_coord_dim == dim) {
    return;
  }

  for (int i = 0; i < dim; i++) {
    for (int j = 0; j < num; j++) {
      coord_h[(size_t)num * i + j] = points->p[j].coord[i];
    }
  }

  double t1 = helper_gettime();
  cudaCheck(cudaMemcpy(coord_d, coord_h, (size_t)num * dim * sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy coord_d");
  double t2 = helper_gettime();

  H2D += t2 - t1;
  if (cpu_gpu_memcpy) *cpu_gpu_memcpy += t2 - t1;

  last_coord_source = points->p;
  last_coord_num = num;
  last_coord_dim = dim;
}

extern "C" float pgain(
    long x,
    Points *points,
    float z,
    long int *numcenters,
    int kmax,
    bool *is_center,
    int *center_table,
    char *switch_membership,
    double *serial,
    double *cpu_gpu_memcpy,
    double *memcpy_back,
    double *gpu_malloc,
    double *kernel)
{
  float gl_cost = 0.0f;
  try{
#ifdef PROFILE_TMP
    double t1 = helper_gettime();
#endif
    int K = (int)(*numcenters);
    int num = (int)points->num;
    int dim = points->dim;
    kmax++;

    int count = 0;
    for (int i = 0; i < num; i++) {
      if (is_center[i]) {
        center_table[i] = count++;
      }
    }

#ifdef PROFILE_TMP
    double t2 = helper_gettime();
    *serial += t2 - t1;
#endif

    double t_alloc1 = helper_gettime();
    bool need_realloc = (num > alloc_num || dim > alloc_dim || kmax > alloc_kcap);
    ensure_capacity(num, dim, kmax);
    double t_alloc2 = helper_gettime();
    if (need_realloc && gpu_malloc) *gpu_malloc += t_alloc2 - t_alloc1;

    update_coords_if_needed(points, cpu_gpu_memcpy);

#ifdef PROFILE_TMP
    double t100 = helper_gettime();
#endif
    for (int i = 0; i < num; i++) {
      p_h[i].weight = points->p[i].weight;
      p_h[i].assign = points->p[i].assign;
      p_h[i].cost = points->p[i].cost;
    }
#ifdef PROFILE_TMP
    double t101 = helper_gettime();
    *serial += t101 - t100;
#endif

    double t7 = helper_gettime();
    cudaCheck(cudaMemcpy(center_table_d, center_table, (size_t)num * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy center_table_d");
    cudaCheck(cudaMemcpy(p_d, p_h, (size_t)num * sizeof(Point_Struct), cudaMemcpyHostToDevice), "cudaMemcpy p_d");
    double t8 = helper_gettime();
    H2D += t8 - t7;
    if (cpu_gpu_memcpy) *cpu_gpu_memcpy += t8 - t7;

    double t9 = helper_gettime();
    cudaCheck(cudaMemset(switch_membership_d, 0, (size_t)num * sizeof(char)), "cudaMemset switch_membership_d");
    cudaCheck(cudaMemset(work_mem_d, 0, (size_t)(K + 1) * num * sizeof(float)), "cudaMemset work_mem_d");

    int blocks = (num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
    pgain_kernel<<<blocks, THREADS_PER_BLOCK, (size_t)dim * sizeof(float)>>>(
        p_d, coord_d, work_mem_d, center_table_d, switch_membership_d, num, dim, x, K);
    cudaCheck(cudaGetLastError(), "pgain_kernel launch");
    cudaCheck(cudaDeviceSynchronize(), "pgain_kernel sync");
    double t10 = helper_gettime();
    KE += t10 - t9;
    if (kernel) *kernel += t10 - t9;

    cudaCheck(cudaMemcpy(switch_membership, switch_membership_d, (size_t)num * sizeof(char), cudaMemcpyDeviceToHost), "cudaMemcpy switch_membership");
    cudaCheck(cudaMemcpy(work_mem_h, work_mem_d, (size_t)(K + 1) * num * sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy work_mem_h");
    double t11 = helper_gettime();
    D2H += t11 - t10;
    if (memcpy_back) *memcpy_back += t11 - t10;

    int numclose = 0;
    gl_cost = z;

    for (int i = 0; i < num; i++) {
      if (is_center[i]) {
        float low = z;
        for (int j = 0; j < num; j++) {
          low += work_mem_h[(size_t)j * (K + 1) + center_table[i]];
        }
        gl_lower[center_table[i]] = low;

        if (low > 0) {
          numclose++;
          work_mem_h[(size_t)i * (K + 1) + K] -= low;
        }
      }
      gl_cost += work_mem_h[(size_t)i * (K + 1) + K];
    }

    if (gl_cost < 0) {
      for (int i = 0; i < num; i++) {
        bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
        if ((switch_membership[i] == '1') || close_center) {
          points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
          points->p[i].assign = x;
        }
      }

      for (int i = 0; i < num; i++) {
        if (is_center[i] && gl_lower[center_table[i]] > 0) {
          is_center[i] = false;
        }
      }

      is_center[x] = true;
      *numcenters = *numcenters + 1 - numclose;
    } else {
      gl_cost = 0;
    }

#ifdef PROFILE_TMP
    double t12 = helper_gettime();
    *serial += t12 - t11;
#endif
    c++;
  }
  catch(std::string msg){
    printf("--cambine:%s\n", msg.c_str());
    freeDevMem();
    _clRelease();
    exit(-1);
  }
  catch(...){
    printf("--cambine: unknow reasons in pgain\n");
  }

  return -gl_cost;
}

